// Update direction accuracy on trade close
async function d1UpdateDirectionOutcome(env, trade) {
  const db = env?.DB;
  const tradeId = String(trade?.id || trade?.trade_id || "").trim();
  if (!db || !tradeId) return;
  try {
    await d1EnsureLearningSchema(env);
    const isLong = trade.direction === "LONG";
    const entryPx = Number(trade.entryPrice) || 0;
    const exitPx = Number(trade.exitPrice) || 0;
    const pnl = Number(trade.pnl) || Number(trade.realizedPnl) || 0;
    const pnlPct = Number(trade.pnlPct) || 0;
    const dirCorrect = pnl > 0 ? 1 : pnl < 0 ? 0 : null;
    const mfe = Number(trade.maxFavorableExcursion) || null;
    const mae = Number(trade.maxAdverseExcursion) || null;
    const status = String(trade.status || "");
    const exitReason = trade.exitReason || trade.exit_reason || null;
    const runId = String(trade.run_id || trade.runId || "").trim() || null;
    let outcomeRes = await db.prepare(
      `UPDATE direction_accuracy SET exit_ts=?, exit_price=?, pnl=?, pnl_pct=?,
       direction_correct=?, max_favorable_excursion=?, max_adverse_excursion=?, status=?,
       exit_reason=?, run_id=COALESCE(run_id, ?10)
       WHERE trade_id=?11`
    ).bind(
      trade.exit_ts || Date.now(), exitPx, pnl, pnlPct,
      dirCorrect, mfe, mae, status,
      exitReason != null ? String(exitReason) : null,
      runId,
      tradeId
    ).run();
    if (Number(outcomeRes?.meta?.changes || 0) === 0) {
      await db.prepare(
        `INSERT OR IGNORE INTO direction_accuracy
          (trade_id, ticker, ts, traded_direction, status, run_id, exit_reason)
         VALUES (?1, ?2, ?3, ?4, ?5, ?6, ?7)`
      ).bind(
        tradeId,
        String(trade?.ticker || "").trim() || null,
        Number(trade?.exit_ts || trade?.entry_ts || Date.now()) || Date.now(),
        String(trade?.direction || "").trim() || null,
        status || "OPEN",
        runId,
        exitReason != null ? String(exitReason) : null,
      ).run();
      await db.prepare(
        `UPDATE direction_accuracy SET exit_ts=?, exit_price=?, pnl=?, pnl_pct=?,
         direction_correct=?, max_favorable_excursion=?, max_adverse_excursion=?, status=?,
         exit_reason=?, run_id=COALESCE(run_id, ?10)
         WHERE trade_id=?11`
      ).bind(
        trade.exit_ts || Date.now(), exitPx, pnl, pnlPct,
        dirCorrect, mfe, mae, status,
        exitReason != null ? String(exitReason) : null,
        runId,
        tradeId
      ).run();
    }
  } catch (e) {
    console.warn("[LEARNING] Failed to update direction outcome:", String(e).slice(0, 150));
  }
}

async function d1PersistTradeExitSnapshot(env, trade, exitSnapshotJson) {
  const db = env?.DB;
  const tradeId = String(trade?.id || trade?.trade_id || "").trim();
  if (!db || !tradeId || !exitSnapshotJson) return;
  try {
    await d1EnsureLearningSchema(env);
    await d1EnsureBacktestRunsSchema(env);
    const runId = String(trade?.run_id || trade?.runId || "").trim() || null;
    const ticker = String(trade?.ticker || "").trim() || null;
    const direction = String(trade?.direction || "").trim() || null;
    const ts = Number(trade?.exit_ts || trade?.entry_ts || Date.now()) || Date.now();
    const status = String(trade?.status || "").trim() || "OPEN";
    const exitReason = String(trade?.exitReason || trade?.exit_reason || "").trim() || null;

    await db.prepare(
      `UPDATE direction_accuracy
          SET exit_snapshot_json = ?1,
              run_id = COALESCE(run_id, ?3)
        WHERE trade_id = ?2`
    ).bind(exitSnapshotJson, tradeId, runId).run();

    await db.prepare(
      `INSERT OR IGNORE INTO direction_accuracy
        (trade_id, ticker, ts, traded_direction, status, run_id, exit_snapshot_json, exit_reason)
       VALUES (?1, ?2, ?3, ?4, ?5, ?6, ?7, ?8)`
    ).bind(
      tradeId,
      ticker,
      ts,
      direction,
      status,
      runId,
      exitSnapshotJson,
      exitReason,
    ).run();

    if (runId) {
      await db.prepare(
        `UPDATE backtest_run_direction_accuracy
            SET exit_snapshot_json = ?1,
                exit_reason = COALESCE(?4, exit_reason)
          WHERE run_id = ?2
            AND trade_id = ?3`
      ).bind(exitSnapshotJson, runId, tradeId, exitReason).run();

      await db.prepare(
        `INSERT OR IGNORE INTO backtest_run_direction_accuracy
          (run_id, trade_id, ticker, ts, exit_snapshot_json, exit_reason)
         VALUES (?1, ?2, ?3, ?4, ?5, ?6)`
      ).bind(runId, tradeId, ticker, ts, exitSnapshotJson, exitReason).run();
    }
  } catch (e) {
    console.warn("[EXIT_SNAP] persist helper failed:", String(e?.message || e).slice(0, 150));
  }
}

async function d1UpdateLearningOnClose(env, trade, tickerData) {
  const db = env?.DB;
  if (!db || !trade?.ticker) return;
  try {
    const ticker = trade.ticker;
    const row = (await db.prepare(
      `SELECT learning_json FROM ticker_profiles WHERE ticker = ?`
    ).bind(ticker).first());
    if (!row?.learning_json) return;

    let learning;
    try { learning = JSON.parse(row.learning_json); } catch (_) { return; }
    if (!learning?.entry_params) return;

    const direction = String(trade.direction || "").toUpperCase();
    const pnlPct = Number(trade.pnlPct) || 0;
    const isWin = pnlPct > 0;
    const mfe = Number(trade.maxFavorableExcursion) || 0;
    const mae = Number(trade.maxAdverseExcursion) || 0;

    const outcomes = learning.recent_outcomes || [];
    outcomes.push({
      ts: Date.now(),
      dir: direction,
      pnl_pct: Math.round(pnlPct * 100) / 100,
      mfe: Math.round(mfe * 100) / 100,
      mae: Math.round(mae * 100) / 100,
      win: isWin,
    });
    if (outcomes.length > 50) outcomes.splice(0, outcomes.length - 50);
    learning.recent_outcomes = outcomes;

    const ep = learning.entry_params;
    const DECAY = 0.05;

    if (mae > 0 && ep.sl_atr_mult) {
      const dAtr = Number(tickerData?.tf_tech?.D?.atr) || Number(tickerData?.atr) || 0;
      if (dAtr > 0) {
        const maeAtrMult = mae / 100 * (Number(trade.entryPrice) || 1) / dAtr;
        if (maeAtrMult > ep.sl_atr_mult * 1.1 && !isWin) {
          ep.sl_atr_mult = Math.round((ep.sl_atr_mult + DECAY * (maeAtrMult - ep.sl_atr_mult)) * 100) / 100;
        }
      }
    }

    if (mfe > 0 && ep.tp_atr_mult) {
      const dAtr = Number(tickerData?.tf_tech?.D?.atr) || Number(tickerData?.atr) || 0;
      if (dAtr > 0) {
        const mfeAtrMult = mfe / 100 * (Number(trade.entryPrice) || 1) / dAtr;
        if (isWin && mfeAtrMult > ep.tp_atr_mult * 1.1) {
          ep.tp_atr_mult = Math.round((ep.tp_atr_mult + DECAY * (mfeAtrMult - ep.tp_atr_mult)) * 100) / 100;
        }
      }
    }

    const recentWins = outcomes.slice(-20).filter(o => o.win).length;
    const recentTotal = Math.min(outcomes.length, 20);
    if (recentTotal >= 5) {
      learning.recent_win_rate = Math.round((recentWins / recentTotal) * 100);
    }

    learning.last_updated = new Date().toISOString();
    const json = JSON.stringify(learning).replace(/'/g, "''");
    await db.prepare(`UPDATE ticker_profiles SET learning_json = ? WHERE ticker = ?`).bind(JSON.stringify(learning), ticker).run();
    const KV = env?.KV_TIMED;
    if (KV) await KV.delete(`timed:profile:${ticker}`).catch(() => {});
    console.log(`[LEARNING_LOOP] ${ticker} profile updated (${direction} ${isWin ? "WIN" : "LOSS"} ${pnlPct.toFixed(1)}%, outcomes=${outcomes.length})`);
  } catch (e) {
    console.warn("[LEARNING_LOOP] Failed:", String(e).slice(0, 200));
  }
}

