                debugObj.check_tickers_twelvedata = Object.fromEntries(checkTickers.map(sym => [sym, tdFlat.filter(e => String(e.symbol || "").toUpperCase() === sym).map(e => ({ symbol: e.symbol, date: e.date }))]));
